	private static final class ResultSnapshot {
		private final String storeName;
		private final List<String> bindingNames;
		private final List<BindingSet> bindings;

		private ResultSnapshot(String storeName, List<String> bindingNames, List<BindingSet> bindings) {
			this.storeName = storeName;
			this.bindingNames = bindingNames;
			this.bindings = bindings;
		}

		private MutableTupleQueryResult asTupleQueryResult() {
			return new MutableTupleQueryResult(bindingNames, bindings);
		}

		private static ResultSnapshot fromTupleQueryResult(String storeName, TupleQueryResult result) {
			List<BindingSet> bindingSets = new ArrayList<>();
			while (result.hasNext()) {
				bindingSets.add(copyBindingSet(result.next()));
			}
			return new ResultSnapshot(storeName, new ArrayList<>(result.getBindingNames()), bindingSets);
		}

		private static ResultSnapshot fromJena(String storeName, ResultSet resultSet) {
			List<String> resultVars = new ArrayList<>(resultSet.getResultVars());
			List<BindingSet> bindingSets = new ArrayList<>();
			while (resultSet.hasNext()) {
				QuerySolution solution = resultSet.nextSolution();
				MapBindingSet bindingSet = new MapBindingSet(resultVars.size());
				for (String resultVar : resultVars) {
					if (solution.contains(resultVar)) {
						bindingSet.addBinding(resultVar, toRdf4jValue(solution.get(resultVar)));
					}
				}
				bindingSets.add(bindingSet);
			}
			return new ResultSnapshot(storeName, resultVars, bindingSets);
		}

		private static BindingSet copyBindingSet(BindingSet bindingSet) {
			MapBindingSet copy = new MapBindingSet(bindingSet.size());
			bindingSet.forEach(binding -> copy.addBinding(binding.getName(), binding.getValue()));
			return copy;
		}
	}
